+)
+
+func TestCheckpointPredStrategy_SatisfiesInterface(t *testing.T) {
+	var _ ContextStrategy = (*CheckpointPredStrategy)(nil)
+}
+
+func TestCheckpointPredStrategy_Name(t *testing.T) {
